    ('the-things-that-really-matter', 1, $$We stop at the windmill for breakfast, The jungle gym is so much fun. I forget my toy.$$, $$[{"role": "BODY", "text": "We stop at the windmill for breakfast, The jungle gym is so much fun.", "bbox": [100.3, 55.7, 466.7, 99.7], "size": 20.0}, {"role": "BODY", "text": "I forget my toy.", "bbox": [775.1, 55.7, 925.6, 75.7], "size": 20.0}]$$),
    ('the-things-that-really-matter', 2, $$I am sad in the car, but Tando is happy. ‘Hooray! Now you can play with me !’ he says.$$, $$[{"role": "BODY", "text": "I am sad in the car, but Tando is happy.", "bbox": [755.9, 155.6, 944.9, 199.6], "size": 20.0}, {"role": "BODY", "text": "‘Hooray! Now you can play with me !’ he says.", "bbox": [737.6, 227.6, 963.2, 273.4], "size": 20.0}]$$),
    ('the-things-that-really-matter', 3, $$We stop at a farm to see some animals. Tando is searching so hard for a springbok, a monkey gets away with his headphones.$$, $$[{"role": "BODY", "text": "We stop at a farm to see some animals. Tando is searching so hard for a springbok,", "bbox": [75.1, 55.7, 491.9, 99.7], "size": 20.0}, {"role": "BODY", "text": "a monkey gets away with his headphones.", "bbox": [647.6, 55.7, 1053.2, 75.7], "size": 20.0}]$$),
    ('the-things-that-really-matter', 4, $$He is sad in the car, but I am happy. ‘Hooray! Now you can sing with me !’ I say.$$, $$[{"role": "BODY", "text": "He is sad in the car, but I am happy.", "bbox": [756.3, 169.8, 944.5, 213.8], "size": 20.0}, {"role": "BODY", "text": "‘Hooray! Now you can sing with me !’ I say.", "bbox": [744.6, 241.8, 956.2, 287.6], "size": 20.0}]$$),
    ('the-things-that-really-matter', 5, $$We stop at a roaring waterfall. We are so excited, we are pushing and pulling. Papa falls in the water, and so does his map.$$, $$[{"role": "BODY", "text": "We stop at a roaring waterfall. We are so excited, we are pushing and pulling.", "bbox": [134.7, 55.7, 432.2, 123.7], "size": 20.0}, {"role": "BODY", "text": "Papa falls in the water, and so does his map.", "bbox": [739.0, 55.7, 961.8, 99.7], "size": 20.0}]$$),
    ('the-things-that-really-matter', 6, $$He is sad in the car, but Mama is happy. ‘Hooray! Now I can help you find our way!’ she says.$$, $$[{"role": "BODY", "text": "He is sad in the car, but Mama is happy.", "bbox": [755.9, 169.8, 945.0, 213.8], "size": 20.0}, {"role": "BODY", "text": "‘Hooray! Now I can help you find our way!’ she says.", "bbox": [715.6, 241.8, 985.2, 287.6], "size": 20.0}]$$),
    ('the-things-that-really-matter', 7, $$We stop at the roadside vendor to buy some mielies. Mama bends over to pick the best ones, and her glasses fall and break.$$, $$[{"role": "BODY", "text": "We stop at the roadside vendor to buy some mielies.", "bbox": [131.1, 57.6, 435.8, 101.6], "size": 20.0}, {"role": "BODY", "text": "Mama bends over to pick the best ones, and her glasses fall and break.", "bbox": [658.3, 57.6, 1042.5, 101.6], "size": 20.0}]$$),
    ('the-things-that-really-matter', 8, $$Mama is sad in the car, but Papa is happy. ‘Hooray! Now we can find our way together !’ Papa says.$$, $$[{"role": "BODY", "text": "Mama is sad in the car, but Papa is happy.", "bbox": [739.5, 157.0, 961.3, 201.0], "size": 20.0}, {"role": "BODY", "text": "‘Hooray! Now we can find our way together !’ Papa says.", "bbox": [694.1, 229.0, 1006.7, 274.8], "size": 20.0}]$$),
    ('the-things-that-really-matter', 9, $$We stop on an ancient hill to get a view of the valley. Papa is making silly jokes for us to smile for the picture, but...$$, $$[{"role": "BODY", "text": "We stop on an ancient hill to get a view of the valley. Papa is making silly jokes for us to smile for the picture,", "bbox": [81.5, 55.7, 485.4, 123.7], "size": 20.0}, {"role": "BODY", "text": "but...", "bbox": [826.7, 55.7, 874.0, 75.7], "size": 20.0}]$$),
