    ('tlotlegos-tea-party', 0, $$Tlotlego is hosting a tea party for the WHOLE family. “How many people are coming for tea, Koko?” “You, me, Mama, and Papa. And your little sister, Tshiamo.” 1 2 3 4 5$$, $$[{"role": "BODY", "text": "Tlotlego is hosting a tea party for the WHOLE family.", "bbox": [232.2, 74.2, 465.1, 109.4], "size": 16.0}, {"role": "BODY", "text": "“How many people are coming for tea, Koko?”", "bbox": [173.3, 132.7, 524.1, 148.7], "size": 16.0}, {"role": "BODY", "text": "“You, me, Mama, and Papa. And your little sister, Tshiamo.”", "bbox": [635.0, 75.1, 867.4, 110.3], "size": 16.0}, {"role": "BODY", "text": "1 2", "bbox": [934.7, 41.8, 1030.1, 91.0], "size": 36.2}, {"role": "BODY", "text": "3", "bbox": [1025.3, 132.6, 1045.9, 164.8], "size": 32.3}, {"role": "BODY", "text": "4", "bbox": [1063.5, 174.6, 1095.6, 216.3], "size": 41.7}, {"role": "BODY", "text": "5", "bbox": [1035.3, 226.2, 1057.9, 261.2], "size": 35.0}]$$),
    ('tlotlegos-tea-party', 1, $$“One, Tlotlego takes two, three, them counts four, from the and the teacups one kitchen. for as Koko!” he 1 2 3 4 5 bestd da$$, $$[{"role": "BODY", "text": "“One, Tlotlego takes two, three, them counts four, from the and the teacups one kitchen. for as Koko!” he", "bbox": [127.3, 184.8, 439.6, 259.3], "size": 16.0}, {"role": "BODY", "text": "1", "bbox": [786.9, 38.4, 813.9, 92.8], "size": 54.4}, {"role": "BODY", "text": "2 3", "bbox": [734.5, 108.3, 787.1, 263.6], "size": 54.3}, {"role": "BODY", "text": "4 5", "bbox": [1038.1, 166.2, 1083.2, 347.9], "size": 76.8}, {"role": "BODY", "text": "bestd da", "bbox": [913.4, 449.0, 948.4, 496.1], "size": 23.3}]$$),
    ('tlotlegos-tea-party', 2, $$Tlotlego goes to the stoep and places the teacups down on the table. 1 2 3 4 bestd da “One, two, three, four, and … ?” “I only see four cups,” says Koko, “but we are five people.” “When I was in the kitchen before, there were five cups!” Tlotlego exclaims.$$, $$[{"role": "BODY", "text": "Tlotlego goes to the stoep and places the teacups down on the table.", "bbox": [289.7, 48.7, 526.5, 103.1], "size": 16.0}, {"role": "BODY", "text": "1 2 3 4", "bbox": [297.0, 163.3, 373.2, 321.0], "size": 38.7}, {"role": "BODY", "text": "bestd da", "bbox": [320.9, 437.7, 355.9, 484.8], "size": 23.3}, {"role": "BODY", "text": "“One, two, three, four, and … ?”", "bbox": [624.6, 71.4, 865.7, 87.4], "size": 16.0}, {"role": "BODY", "text": "“I only see four cups,” says Koko,", "bbox": [620.7, 110.7, 869.6, 126.7], "size": 16.0}, {"role": "BODY", "text": "“but we are five people.”", "bbox": [652.5, 149.1, 837.8, 165.1], "size": 16.0}, {"role": "BODY", "text": "“When I was in the kitchen before, there were five cups!” Tlotlego exclaims.", "bbox": [594.2, 351.4, 896.1, 386.6], "size": 16.0}]$$),
