    ('tlotlegos-tea-party', 4, $$1 2 3 4 bestd da Tlotlego goes to the stoep and places the plates next to the teacups. “One, two, three, four, and … ?” “I only see four plates,” says Koko, “but we are five people.”$$, $$[{"role": "BODY", "text": "1", "bbox": [335.2, 68.7, 354.4, 107.4], "size": 38.7}, {"role": "BODY", "text": "2", "bbox": [361.5, 141.1, 386.4, 174.7], "size": 33.6}, {"role": "BODY", "text": "3", "bbox": [333.6, 228.9, 354.2, 261.1], "size": 32.3}, {"role": "BODY", "text": "4", "bbox": [416.7, 245.5, 448.8, 287.2], "size": 41.7}, {"role": "BODY", "text": "bestd da", "bbox": [344.8, 442.7, 379.9, 489.8], "size": 23.3}, {"role": "BODY", "text": "Tlotlego goes to the stoep and places the plates next to the teacups.", "bbox": [606.8, 51.8, 896.6, 87.0], "size": 16.0}, {"role": "BODY", "text": "“One, two, three, four, and … ?”", "bbox": [635.2, 118.6, 868.2, 134.6], "size": 16.0}, {"role": "BODY", "text": "“I only see four plates,” says Koko,", "bbox": [621.5, 176.2, 881.9, 192.2], "size": 16.0}, {"role": "BODY", "text": "“but we are five people.”", "bbox": [659.1, 214.6, 844.3, 230.6], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 5, $$1 2 3 4 5 Tlotlego counts the biscuits as he takes them from the jar. “One, two, three, four, and five!”$$, $$[{"role": "BODY", "text": "1 2 3", "bbox": [69.1, 46.5, 128.6, 292.9], "size": 54.7}, {"role": "BODY", "text": "4 5", "bbox": [443.2, 59.7, 506.8, 258.3], "size": 80.4}, {"role": "BODY", "text": "Tlotlego counts the biscuits as he takes them from the jar.", "bbox": [631.7, 117.7, 1069.1, 133.7], "size": 16.0}, {"role": "BODY", "text": "“One, two, three, four, and five!”", "bbox": [724.8, 155.2, 976.0, 171.2], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 6, $$Tlotlego goes to the stoep and places the biscuits on the plates. “One, two, three, four, and … ?” “I only see four biscuits,” says Koko, “but we are five people.”$$, $$[{"role": "BODY", "text": "Tlotlego goes to the stoep and places the biscuits on the plates.", "bbox": [158.1, 81.6, 408.9, 116.8], "size": 16.0}, {"role": "BODY", "text": "“One, two, three, four, and … ?”", "bbox": [801.1, 81.6, 1042.2, 97.6], "size": 16.0}, {"role": "BODY", "text": "“I only see four biscuits,” says Koko,", "bbox": [786.5, 120.9, 1056.7, 136.9], "size": 16.0}, {"role": "BODY", "text": "“but we are five people.”", "bbox": [829.0, 159.3, 1014.2, 175.3], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 7, $$? ? ? ? ? Tlotlego is very confused. He knows he has been counting correctly. Before he had HOW five did biscuits, the biscuits and become now there less? are only four.$$, $$[{"role": "SFX", "text": "?", "bbox": [55.6, 40.8, 90.8, 96.6], "size": 55.8}, {"role": "SFX", "text": "?", "bbox": [57.9, 275.8, 87.4, 325.4], "size": 49.6}, {"role": "SFX", "text": "?", "bbox": [399.4, 46.7, 436.7, 98.8], "size": 52.1}, {"role": "SFX", "text": "?", "bbox": [424.2, 176.3, 462.6, 233.2], "size": 56.9}, {"role": "SFX", "text": "?", "bbox": [438.8, 295.4, 477.1, 352.2], "size": 56.9}, {"role": "BODY", "text": "Tlotlego is very confused. He knows he has been counting correctly.", "bbox": [690.4, 211.8, 1010.4, 247.0], "size": 16.0}, {"role": "BODY", "text": "Before he had HOW five did biscuits, the biscuits and become now there less? are only four.", "bbox": [639.7, 270.3, 1061.1, 324.7], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 8, $$1 2 3 4 5 Tlotlego counts the sugar cubes as he takes them from the jar. “One, two, three, four, and five!”$$, $$[{"role": "BODY", "text": "1", "bbox": [138.5, 56.8, 165.5, 111.2], "size": 54.4}, {"role": "BODY", "text": "2", "bbox": [79.6, 142.1, 118.6, 194.8], "size": 52.7}, {"role": "BODY", "text": "3", "bbox": [102.2, 257.1, 137.9, 313.0], "size": 55.9}, {"role": "BODY", "text": "4 5", "bbox": [416.6, 152.9, 480.1, 354.6], "size": 80.4}, {"role": "BODY", "text": "Tlotlego counts the sugar cubes as he takes them from the jar.", "bbox": [704.4, 196.8, 996.4, 232.0], "size": 16.0}, {"role": "BODY", "text": "“One, two, three, four, and five!”", "bbox": [729.3, 255.3, 971.5, 271.3], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 9, $$5 1 2 3 4 Tlotlego goes to the stoep and places the sugar cubes on the table. This time, he is sure he hears a giggle. “One, two, three, four, and … ?” “Five!” shouts a voice from under the table.$$, $$[{"role": "BODY", "text": "5", "bbox": [414.6, 71.7, 478.2, 174.0], "size": 102.3}, {"role": "BODY", "text": "1 2", "bbox": [934.2, 32.6, 1014.7, 71.3], "size": 36.2}, {"role": "BODY", "text": "3", "bbox": [1078.4, 33.8, 1099.0, 66.1], "size": 32.3}, {"role": "BODY", "text": "4", "bbox": [1047.9, 80.7, 1080.0, 122.3], "size": 41.7}, {"role": "BODY", "text": "Tlotlego goes to the stoep and places the sugar cubes on the table.", "bbox": [769.2, 231.6, 1089.6, 266.8], "size": 16.0}, {"role": "BODY", "text": "This time, he is sure he hears a giggle.", "bbox": [786.3, 290.1, 1072.5, 306.1], "size": 16.0}, {"role": "BODY", "text": "“One, two, three, four, and … ?”", "bbox": [812.9, 328.5, 1045.9, 344.5], "size": 16.0}, {"role": "BODY", "text": "“Five!” shouts a voice from under the table.", "bbox": [749.2, 481.8, 1083.3, 497.8], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 10, $$FIVE! Tlotlego bends down to look under the table. To his shock, he sees a complete tea set laid out under the table! There are the missing teacup, plate, biscuit, and sugar cube.$$, $$[{"role": "SFX", "text": "FIVE!", "bbox": [643.1, 144.1, 735.2, 184.1], "size": 40.0}, {"role": "BODY", "text": "Tlotlego bends down to look under the table. To his shock, he sees a complete tea set laid out under the table!", "bbox": [34.5, 434.2, 532.4, 469.4], "size": 16.0}, {"role": "BODY", "text": "There are the missing teacup, plate, biscuit, and sugar cube.", "bbox": [56.9, 492.7, 510.0, 508.7], "size": 16.0}]$$),
    ('tlotlegos-tea-party', 11, $$When work, One, Mama they two, 1 three and all have Papa of them tea come on having the home stoep. tea from at the table, and two of them having tea below! 4 5 1 2 2 best dad 3 3 4$$, $$[{"role": "BODY", "text": "When work, One, Mama they two, 1 three and all have Papa of them tea come on having the home stoep. tea from at the table,", "bbox": [34.0, 54.6, 344.1, 140.1], "size": 16.0}, {"role": "BODY", "text": "and two of them having tea below!", "bbox": [91.8, 215.5, 232.4, 250.7], "size": 16.0}, {"role": "BODY", "text": "4", "bbox": [163.0, 307.6, 195.1, 349.3], "size": 41.7}, {"role": "BODY", "text": "5", "bbox": [274.4, 360.1, 304.3, 428.1], "size": 68.0}, {"role": "BODY", "text": "1", "bbox": [426.0, 76.1, 445.2, 114.8], "size": 38.7}, {"role": "BODY", "text": "2", "bbox": [516.0, 89.7, 540.9, 123.3], "size": 33.6}, {"role": "BODY", "text": "2", "bbox": [626.5, 83.4, 651.4, 117.0], "size": 33.6}, {"role": "BODY", "text": "best dad", "bbox": [621.8, 297.6, 646.2, 333.6], "size": 16.2}, {"role": "BODY", "text": "3", "bbox": [933.1, 57.9, 953.7, 90.2], "size": 32.3}, {"role": "BODY", "text": "3", "bbox": [798.3, 235.5, 818.9, 267.8], "size": 32.3}, {"role": "BODY", "text": "4", "bbox": [767.8, 282.4, 799.9, 324.0], "size": 41.7}]$$),
