    ('tumi-goes-to-the-park', 0, $$It’s Tumi’s first trip to the park.$$, $$[{"role": "BODY", "text": "It’s Tumi’s first trip to the park.", "bbox": [22.4, 382.9, 334.8, 417.9], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 1, $$“Mama, what’s that? ” “It’s a slide,” says Mama. “May I go on it?” asks Tumi. “Of course!” says Mama.$$, $$[{"role": "BODY", "text": "“Mama, what’s that? ” “It’s a slide,” says Mama.", "bbox": [129.4, 163.4, 437.5, 241.9], "size": 23.8}, {"role": "BODY", "text": "“May I go on it?” asks Tumi.", "bbox": [158.2, 341.9, 408.8, 361.9], "size": 20.0}, {"role": "BODY", "text": "“Of course!” says Mama.", "bbox": [171.2, 389.9, 395.7, 409.9], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 2, $$“Wheeeee!”$$, $$[{"role": "SFX", "text": "“Wheeeee!”", "bbox": [748.5, 457.3, 952.3, 492.3], "size": 35.0}]$$),
    ('tumi-goes-to-the-park', 3, $$“Look Mama, I swing like a m o n k e y . ”$$, $$[{"role": "BODY", "text": "“Look Mama, I swing like a m o n k e y . ”", "bbox": [708.7, 391.8, 1011.8, 525.7], "size": 33.1}]$$),
    ('tumi-goes-to-the-park', 4, $$“I just went past you ten times, Mama!” says Tumi. “You “Clever know girl! how says to Mama. count!”$$, $$[{"role": "BODY", "text": "“I just went past you ten times, Mama!” says Tumi.", "bbox": [90.8, 84.9, 279.1, 177.9], "size": 23.8}, {"role": "BODY", "text": "“You “Clever know girl! how says to Mama. count!”", "bbox": [861.9, 107.6, 1098.3, 151.6], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 5, $$“Do you want to play?” asks Tumi. “Yes!” says the boy.$$, $$[{"role": "BODY", "text": "“Do you want to play?” asks Tumi.", "bbox": [686.0, 84.2, 897.1, 128.2], "size": 20.0}, {"role": "BODY", "text": "“Yes!” says the boy.", "bbox": [702.8, 156.2, 880.3, 176.2], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 6, $$“I’m Tumi.” “I’m Zakhe.”$$, $$[{"role": "BODY", "text": "“I’m Tumi.”", "bbox": [127.5, 144.5, 224.0, 164.5], "size": 20.0}, {"role": "BODY", "text": "“I’m Zakhe.”", "bbox": [906.6, 374.8, 1015.3, 394.8], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 7, $$Tumi sees the sandpit. “Let’s build a sandcastle!” says Tumi.$$, $$[{"role": "BODY", "text": "Tumi sees the sandpit.", "bbox": [180.7, 179.9, 386.3, 199.9], "size": 20.0}, {"role": "BODY", "text": "“Let’s build a sandcastle!” says Tumi.", "bbox": [136.9, 259.6, 430.0, 407.5], "size": 32.5}]$$),
    ('tumi-goes-to-the-park', 8, $$$$, $$[]$$),
    ('tumi-goes-to-the-park', 9, $$“I’m taking a photo for Gogo,” says Mama.$$, $$[{"role": "BODY", "text": "“I’m taking a photo for Gogo,” says Mama.", "bbox": [96.8, 263.2, 301.7, 307.2], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 10, $$“It’s time to go home now, Tumi,” says Mama. “Bye, Zakhe!” waves Tumi. “Bye, Tumi!” says Zakhe. “See you next time!”$$, $$[{"role": "BODY", "text": "“It’s time to go home now, Tumi,” says Mama.", "bbox": [236.7, 114.7, 474.8, 158.7], "size": 20.0}, {"role": "BODY", "text": "“Bye, Zakhe!” waves Tumi.", "bbox": [238.8, 194.2, 472.6, 255.7], "size": 27.5}, {"role": "BODY", "text": "“Bye, Tumi!” says Zakhe.", "bbox": [796.5, 129.2, 1007.8, 190.7], "size": 27.5}, {"role": "BODY", "text": "“See you next time!”", "bbox": [810.0, 216.7, 994.3, 236.7], "size": 20.0}]$$),
    ('tumi-goes-to-the-park', 11, $$“Mama, thank you for bringing me to the park,” says Tumi.$$, $$[{"role": "BODY", "text": "“Mama, thank you for bringing me to the park,” says Tumi.", "bbox": [154.7, 244.3, 412.2, 322.9], "size": 23.8}]$$),
