    ('where-is-lulu', 0, $$“Oh, no!”$$, $$[{"role": "SFX", "text": "“Oh, no!”", "bbox": [129.2, 260.7, 437.8, 340.7], "size": 80.0}]$$),
    ('where-is-lulu', 1, $$“Lulu! It’s time to go,” calls Ma.$$, $$[{"role": "BODY", "text": "“Lulu! It’s time to go,” calls Ma.", "bbox": [132.1, 255.2, 434.8, 325.6], "size": 32.0}]$$),
    ('where-is-lulu', 2, $$Where is Lulu? Is she under the sofa? Is she behind the curtain?$$, $$[{"role": "BODY", "text": "Where is Lulu? Is she under the sofa? Is she behind the curtain?", "bbox": [93.5, 138.0, 467.1, 246.8], "size": 32.0}]$$),
    ('where-is-lulu', 3, $$Where is Lulu? Is she next to the stove? Is she in the cupboard?$$, $$[{"role": "BODY", "text": "Where is Lulu? Is she next to the stove? Is she in the cupboard?", "bbox": [93.5, 135.9, 446.4, 244.7], "size": 32.0}]$$),
    ('where-is-lulu', 4, $$“Lulu! It’s time to go. Where are you?” calls Ma.$$, $$[{"role": "BODY", "text": "“Lulu! It’s time to go. Where are you?” calls Ma.", "bbox": [56.7, 255.2, 435.5, 325.6], "size": 32.0}]$$),
    ('where-is-lulu', 5, $$“There you are!” “I don’t want to gooo!”$$, $$[{"role": "BODY", "text": "“There you are!”", "bbox": [56.7, 236.0, 291.1, 268.0], "size": 32.0}, {"role": "BODY", "text": "“I don’t want to gooo!”", "bbox": [56.7, 312.8, 380.6, 344.8], "size": 32.0}]$$),
