    ('whos-that-baby', 5, $$My waving hands. That baby’s waving hands.$$, $$[{"role": "BODY", "text": "My waving hands.", "bbox": [126.8, 91.3, 440.2, 129.3], "size": 38.0}, {"role": "BODY", "text": "That baby’s waving hands.", "bbox": [624.8, 483.5, 1078.9, 521.5], "size": 38.0}]$$),
