    ('whos-that-baby', 10, $$I make a funny face. So does that baby.$$, $$[{"role": "BODY", "text": "I make a funny face.", "bbox": [109.5, 91.3, 457.5, 129.3], "size": 38.0}, {"role": "BODY", "text": "So does that baby.", "bbox": [697.2, 483.5, 1003.5, 521.5], "size": 38.0}]$$),
