    ('why-birds-sing-at-dawn', 0, $$A long time ago, in the forest of Happy-Land, birds and trees could talk to each other. Tweet Tweet Tweet Tweet Bla Tweet Tweet$$, $$[{"role": "BODY", "text": "A long time ago, in the forest of Happy-Land, birds and trees could talk to each other.", "bbox": [100.9, 193.7, 466.1, 271.9], "size": 23.0}, {"role": "BODY", "text": "Tweet", "bbox": [326.6, 363.3, 369.0, 391.5], "size": 18.3}, {"role": "BODY", "text": "Tweet Tweet", "bbox": [579.3, 325.1, 633.5, 395.4], "size": 19.0}, {"role": "BODY", "text": "Tweet", "bbox": [506.4, 333.0, 548.8, 361.2], "size": 18.3}, {"role": "BODY", "text": "Bla", "bbox": [844.4, 260.8, 870.6, 283.6], "size": 17.4}, {"role": "BODY", "text": "Tweet Tweet", "bbox": [773.0, 313.2, 851.0, 371.4], "size": 18.2}]$$),
    ('why-birds-sing-at-dawn', 1, $$There was a bird family with three children: Blue, Pink and Yellow. They all lived on a big wise tree called Mamango.$$, $$[{"role": "BODY", "text": "There was a bird family with three children: Blue, Pink and Yellow. They all lived on a big wise tree called Mamango.", "bbox": [53.6, 172.8, 509.2, 292.8], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 2, $$Mama Birdie’s voice was beautiful! She would wake up early to sing her song.$$, $$[{"role": "BODY", "text": "Mama Birdie’s voice was beautiful! She would wake up early to sing her song.", "bbox": [80.6, 352.1, 483.5, 402.7], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 3, $$But drought set in on the land. Rivers dried up and leaves fell off.$$, $$[{"role": "BODY", "text": "But drought set in on the land. Rivers dried up and leaves fell off.", "bbox": [657.8, 155.1, 1043.0, 205.7], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 4, $$Mamango thought long and hard. “Maybe we should get the magic worm that brings rain. But who can go?”$$, $$[{"role": "BODY", "text": "Mamango thought long and hard. “Maybe we should get the magic worm that brings rain. But who can go?”", "bbox": [649.0, 346.9, 1051.8, 439.2], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 5, $$“I will go. I am not afraid,” Mama Birdie said.$$, $$[{"role": "BODY", "text": "“I will go. I am not afraid,” Mama Birdie said.", "bbox": [712.6, 360.6, 988.3, 425.4], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 6, $$Everyone missed Mama Birdie, and her song. Would she ever find her way back home?$$, $$[{"role": "BODY", "text": "Everyone missed Mama Birdie, and her song. Would she ever find her way back home?", "bbox": [86.7, 353.9, 480.2, 432.1], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 7, $$“What if we sing Mama’s song?” Yellow asked. “Mama said if we sing her song, she will find her way back.” “But I don’t know how to sing!” cried Pink.$$, $$[{"role": "BODY", "text": "“What if we sing Mama’s song?” Yellow asked. “Mama said if we sing her song, she will find her way back.”", "bbox": [97.4, 143.8, 469.6, 277.9], "size": 23.0}, {"role": "BODY", "text": "“But I don’t know how to sing!” cried Pink.", "bbox": [689.8, 148.0, 1011.1, 212.7], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 8, $$“Have you tried singing?” Mamango asked.$$, $$[{"role": "BODY", "text": "“Have you tried singing?” Mamango asked.", "bbox": [719.6, 378.3, 981.3, 443.1], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 9, $$“I have tried singing,” said Yellow. “I can teach you.”$$, $$[{"role": "BODY", "text": "“I have tried singing,” said Yellow. “I can teach you.”", "bbox": [171.9, 231.2, 395.1, 337.8], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 10, $$Early the next morning, Yellow sang Mama’s song: “It’s a beautifulmorning! We wakeupand shine!” And rain started falling.$$, $$[{"role": "BODY", "text": "Early the next morning, Yellow sang Mama’s song:", "bbox": [124.1, 112.4, 442.9, 163.0], "size": 23.0}, {"role": "BODY", "text": "“It’s a beautifulmorning!", "bbox": [88.3, 187.9, 342.9, 252.6], "size": 24.2}, {"role": "BODY", "text": "We wakeupand shine!”", "bbox": [188.4, 276.6, 433.9, 345.9], "size": 25.2}, {"role": "BODY", "text": "And rain started falling.", "bbox": [158.2, 385.3, 408.8, 408.3], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 11, $$Eventually, all the birds joined Yellow in song. Mama Birdie found her way back to Happy-Land. And from then on, birds sang at dawn.$$, $$[{"role": "BODY", "text": "Eventually, all the birds joined Yellow in song. Mama Birdie found her way back to Happy-Land. And from then on, birds sang at dawn.", "bbox": [642.8, 75.6, 1043.8, 237.3], "size": 23.0}]$$),
    ('why-birds-sing-at-dawn', 12, $$$$, $$[]$$),
    ('why-birds-sing-at-dawn', 13, $$$$, $$[]$$),
    ('why-is-there-a-hole-in-the-wall', 0, $$Lungisa lived in a village called esiKhaleni or Place of Noise. Some people also called it Hole-in-the-Wall.$$, $$[{"role": "BODY", "text": "Lungisa lived in a village called esiKhaleni or Place of Noise.", "bbox": [91.4, 73.0, 475.7, 117.0], "size": 20.0}, {"role": "BODY", "text": "Some people also called it Hole-in-the-Wall.", "bbox": [647.3, 78.5, 1053.7, 98.5], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 1, $$“Why is there a hole in the wall?” Lungisa asked his mother. “Because one of the sea-people used a giant fish head to break through the wall so that he could get to the woman he loved.”$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his mother.", "bbox": [128.7, 226.9, 438.5, 270.9], "size": 20.0}, {"role": "BODY", "text": "“Because one of the sea-people used a giant fish head to break through the wall so that he could get to the woman he loved.”", "bbox": [60.0, 298.9, 507.1, 366.9], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 2, $$“Interesting,” said Lungisa.$$, $$[{"role": "BODY", "text": "“Interesting,” said Lungisa.", "bbox": [154.9, 286.9, 412.1, 306.9], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 3, $$“Why is there a hole in the wall?” Lungisa asked his teacher.$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his teacher.", "bbox": [695.6, 214.7, 1005.4, 258.7], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 4, $$“Because waves crashed against the rock for millions of years, and made a hole in the sandstone,” said his teacher.$$, $$[{"role": "BODY", "text": "“Because waves crashed against the rock for millions of years, and made a hole in the sandstone,” said his teacher.", "bbox": [81.8, 262.9, 485.3, 330.9], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 5, $$“Interesting,” said Lungisa.$$, $$[{"role": "BODY", "text": "“Interesting,” said Lungisa.", "bbox": [154.9, 286.9, 412.1, 306.9], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 6, $$“Why is there a hole in the wall?” Lungisa asked his granny. “So that our ancestors will have a gateway to us.” “Interesting,” said Lungisa.$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his granny.", "bbox": [695.6, 88.8, 1005.4, 132.8], "size": 20.0}, {"role": "BODY", "text": "“So that our ancestors will have a gateway to us.”", "bbox": [694.1, 184.8, 1006.9, 228.8], "size": 20.0}, {"role": "BODY", "text": "“Interesting,” said Lungisa.", "bbox": [721.9, 280.8, 979.0, 300.8], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 7, $$“Why is there a hole in the wall?” Lungisa asked his auntie. “It is a window to God.” “Interesting,” said Lungisa.$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his auntie.", "bbox": [128.7, 168.2, 438.5, 212.2], "size": 20.0}, {"role": "BODY", "text": "“It is a window to God.”", "bbox": [171.9, 264.2, 395.1, 284.2], "size": 20.0}, {"role": "BODY", "text": "“Interesting,” said Lungisa.", "bbox": [154.9, 336.2, 412.1, 356.2], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 8, $$“Why is there a hole in the wall?” Lungisa asked his friend. “Because a ship crashed into the wall.” “Interesting,” said Lungisa.$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his friend.", "bbox": [695.6, 202.9, 1005.4, 246.9], "size": 20.0}, {"role": "BODY", "text": "“Because a ship crashed into the wall.”", "bbox": [669.9, 298.9, 1031.1, 318.9], "size": 20.0}, {"role": "BODY", "text": "“Interesting,” said Lungisa.", "bbox": [721.9, 370.9, 979.0, 390.9], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 9, $$“Why is there a hole in the wall?” Lungisa asked his little sister. “So that my brother will keep on asking questions,” she said.$$, $$[{"role": "BODY", "text": "“Why is there a hole in the wall?” Lungisa asked his little sister.", "bbox": [56.8, 303.5, 267.9, 395.5], "size": 20.0}, {"role": "BODY", "text": "“So that my brother will keep on asking questions,” she said.", "bbox": [66.7, 423.5, 257.9, 491.5], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 10, $$And Lungisa laughed.$$, $$[{"role": "BODY", "text": "And Lungisa laughed.", "bbox": [184.6, 252.2, 382.4, 272.2], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 11, $$But he kept on asking.$$, $$[{"role": "BODY", "text": "But he kept on asking.", "bbox": [181.4, 91.3, 385.6, 111.3], "size": 20.0}]$$),
    ('why-is-there-a-hole-in-the-wall', 12, $$$$, $$[]$$),
    ('why-is-there-a-hole-in-the-wall', 13, $$$$, $$[]$$),
    ('why-the-owl-never-sleeps', 0, $$Ages ago, when rocks were still soft and trees could talk, all the animals lived on land under one big shed.$$, $$[{"role": "BODY", "text": "Ages ago, when rocks were still soft and trees could talk, all the animals lived on land under one big shed.", "bbox": [143.2, 233.4, 423.7, 311.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 1, $$They took care of each other and protected one another from human trouble all day and night.$$, $$[{"role": "BODY", "text": "They took care of each other and protected one another from human trouble all day and night.", "bbox": [136.3, 233.4, 430.6, 311.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 2, $$At sunset, the elephants trumpeted and the birds chirped along in harmony, while the peacock danced.$$, $$[{"role": "BODY", "text": "At sunset, the elephants trumpeted and the birds chirped along in harmony, while the peacock danced.", "bbox": [128.2, 233.4, 438.8, 311.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 3, $$One night, it was Mr Owl’s turn to guard the animals as they slept.$$, $$[{"role": "BODY", "text": "One night, it was Mr Owl’s turn to guard the animals as they slept.", "bbox": [124.9, 248.4, 442.0, 296.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 4, $$He stayed up watching far and wide for any sign of humans.$$, $$[{"role": "BODY", "text": "He stayed up watching far and wide for any sign of humans.", "bbox": [193.6, 233.4, 373.3, 311.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 5, $$Suddenly the bush in front of him crackled and shook.$$, $$[{"role": "BODY", "text": "Suddenly the bush in front of him crackled and shook.", "bbox": [56.7, 191.0, 319.3, 239.0], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 6, $$“Aww!” Mr Owl was trapped in the hands of a small boy. Owl hooted and ruffled his feathers. There was even a toot.$$, $$[{"role": "BODY", "text": "“Aww!” Mr Owl was trapped in the hands of a small boy.", "bbox": [172.2, 188.4, 394.8, 236.4], "size": 18.0}, {"role": "BODY", "text": "Owl hooted and ruffled his feathers. There was even a toot.", "bbox": [141.1, 278.4, 425.8, 326.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 7, $$“Please don’t roast me! Take the other animals. I am too wise to be eaten – I won’t be as delicious.”$$, $$[{"role": "BODY", "text": "“Please don’t roast me! Take the other animals. I am too wise to be eaten – I won’t be as delicious.”", "bbox": [176.4, 218.4, 390.6, 326.4], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 8, $$The boy shrugged, heading under the animals’ shed. He lit a fire, waking the animals from their sleep. “Fire!” they shouted, as they scattered all over.$$, $$[{"role": "BODY", "text": "The boy shrugged, heading under the animals’ shed. He lit a fire, waking the animals from their sleep.", "bbox": [152.4, 168.1, 414.9, 276.1], "size": 18.0}, {"role": "BODY", "text": "“Fire!” they shouted, as they scattered all over.", "bbox": [101.9, 332.1, 465.0, 350.1], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 9, $$The insects hid underground. Some animals ran for the river and never came back. The birds flew deep into the night sky.$$, $$[{"role": "BODY", "text": "The insects hid underground.", "bbox": [169.0, 181.3, 397.9, 199.3], "size": 18.0}, {"role": "BODY", "text": "Some animals ran for the river and never came back.", "bbox": [165.6, 241.3, 401.7, 289.3], "size": 18.0}, {"role": "BODY", "text": "The birds flew deep into the night sky.", "bbox": [133.2, 331.3, 433.7, 349.3], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 10, $$The humans left with the cats, cows and dogs, leaving Mr Owl ashamed. “They must never see me again.”$$, $$[{"role": "BODY", "text": "The humans left with the cats, cows and dogs, leaving Mr Owl ashamed. “They must never see me again.”", "bbox": [206.9, 195.8, 489.0, 273.8], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 11, $$From that night, he vowed never to show his face in daylight … only at night to eat and stretch his wings.$$, $$[{"role": "BODY", "text": "From that night, he vowed never to show his face in daylight … only at night to eat and stretch his wings.", "bbox": [49.6, 57.6, 372.2, 135.6], "size": 18.0}]$$),
    ('why-the-owl-never-sleeps', 12, $$$$, $$[]$$),
    ('why-the-owl-never-sleeps', 13, $$$$, $$[]$$),
    ('wiggle-jiggle', 0, $$Wiggle jiggle wriggle! I am a wiggly worm.$$, $$[{"role": "BODY", "text": "Wiggle jiggle wriggle!", "bbox": [66.6, 165.3, 497.3, 416.5], "size": 72.9}, {"role": "BODY", "text": "I am a wiggly worm.", "bbox": [831.8, 389.4, 1078.7, 415.4], "size": 26.0}]$$),
    ('wiggle-jiggle', 1, $$Flowers my favouritefood. and leavesare Yummy in my tummy!$$, $$[{"role": "BODY", "text": "Flowers my favouritefood. and leavesare", "bbox": [56.1, 58.9, 336.3, 207.1], "size": 30.1}, {"role": "BODY", "text": "Yummy in", "bbox": [313.4, 165.5, 542.2, 346.1], "size": 55.3}, {"role": "BODY", "text": "my tummy!", "bbox": [605.6, 347.9, 866.0, 446.5], "size": 51.8}]$$),
    ('wiggle-jiggle', 2, $$Wiggle jiggle wriggle! I am a wiggly worm.$$, $$[{"role": "BODY", "text": "Wiggle jiggle wriggle!", "bbox": [67.3, 138.5, 497.3, 374.6], "size": 72.9}, {"role": "BODY", "text": "I am a wiggly worm.", "bbox": [685.9, 356.8, 765.4, 445.2], "size": 26.0}]$$),
    ('wiggle-jiggle', 3, $$I love the rain. Pitter- patter on the leaves.$$, $$[{"role": "BODY", "text": "I love the rain. Pitter- patter on the leaves.", "bbox": [61.8, 254.5, 808.4, 392.6], "size": 30.9}]$$),
    ('wiggle-jiggle', 4, $$Watch me wiggle and dance. Wiggleggle ji wriggle!$$, $$[{"role": "BODY", "text": "Watch me wiggle and dance. Wiggleggle ji wriggle!", "bbox": [708.2, 121.5, 1083.8, 399.6], "size": 74.1}]$$),
    ('wiggle-jiggle', 5, $$POO!!! My magic makes poo plants grow BIG.$$, $$[{"role": "SFX", "text": "POO!!!", "bbox": [48.9, 53.2, 335.3, 165.4], "size": 103.2}, {"role": "BODY", "text": "My magic makes poo plants grow BIG.", "bbox": [622.2, 107.1, 913.4, 253.1], "size": 43.0}]$$),
    ('wiggle-jiggle', 6, $$I love to see my plants grow. Yellow,and red, green. blue$$, $$[{"role": "BODY", "text": "I love to see my plants grow. Yellow,and red, green. blue", "bbox": [629.5, 352.5, 1065.2, 524.5], "size": 40.6}]$$),
    ('wiggle-jiggle', 7, $$Wigglejiggle wriggle! I am a wiggly worm.$$, $$[{"role": "BODY", "text": "Wigglejiggle wriggle! I am a wiggly worm.", "bbox": [228.5, 140.6, 1075.2, 361.5], "size": 31.8}]$$),
    ('wiggle-jiggle', 8, $$Wiggle in when the garden. you see me Wiggleggle ji wriggle!$$, $$[{"role": "BODY", "text": "Wiggle in when the garden. you see me", "bbox": [139.6, 119.3, 444.3, 176.5], "size": 26.0}, {"role": "SFX", "text": "Wiggleggle ji wriggle!", "bbox": [659.3, 56.2, 1034.8, 295.1], "size": 83.0}]$$),
    ('wiggle-jiggle', 9, $$Where am I now? I’m here in my cocoon!$$, $$[{"role": "BODY", "text": "Where am I now?", "bbox": [75.8, 82.8, 472.9, 214.8], "size": 60.0}, {"role": "BODY", "text": "I’m here in my cocoon!", "bbox": [623.6, 363.7, 969.7, 523.1], "size": 64.8}]$$),
    ('wiggle-jiggle', 10, $$Oh wait! I’m not a wiggly worm!$$, $$[{"role": "BODY", "text": "Oh wait!", "bbox": [168.4, 259.8, 398.6, 319.8], "size": 60.0}, {"role": "BODY", "text": "I’m not a wiggly worm!", "bbox": [650.8, 301.3, 899.0, 516.8], "size": 59.1}]$$),
    ('wiggle-jiggle', 11, $$Flitter flutter flitter! I am a butterfly!$$, $$[{"role": "BODY", "text": "Flitter flutter flitter!", "bbox": [79.0, 135.5, 463.6, 347.1], "size": 72.4}, {"role": "SFX", "text": "I am a butterfly!", "bbox": [127.1, 438.8, 241.1, 496.0], "size": 26.0}]$$),
