    ('woof-woof', 1, $$Don’t be scared.$$, $$[{"role": "BODY", "text": "Don’t be scared.", "bbox": [737.3, 114.4, 963.5, 142.4], "size": 28.0}]$$),
    ('woof-woof', 2, $$Woof-woof out!$$, $$[{"role": "BODY", "text": "Woof-woof out!", "bbox": [658.5, 142.5, 876.5, 170.5], "size": 28.0}]$$),
    ('woof-woof', 3, $$Look, Doggy’s bringing the ball.$$, $$[{"role": "BODY", "text": "Look, Doggy’s bringing the ball.", "bbox": [165.4, 184.6, 401.6, 246.2], "size": 28.0}]$$),
