    ('woof-woof', 5, $$Doggy wants to play. Play?$$, $$[{"role": "BODY", "text": "Doggy wants to play.", "bbox": [325.9, 86.0, 508.9, 147.7], "size": 28.0}, {"role": "BODY", "text": "Play?", "bbox": [381.4, 244.8, 453.4, 272.8], "size": 28.0}]$$),
